  (14, 'Which font property should be used to establish a clear visual hierarchy in reports?', 'Varying font sizes, weights (bold/regular), and colors strategically', 'Using different font families for every word', 'Always using uppercase letters', 'Centering all text fields', 'A', 2, 14),
  (14, 'When designing a dashboard, what is the best practice for using color?', 'Use as many vibrant colors as possible to make it look active', 'Use a neutral palette (greys) with one single accent color to highlight key insights', 'Use black and white only', 'Use different colors for every category', 'B', 2, 15),
