-- KPITB Data Analytics LMS Questions Database Seed File
-- Exactly 20 premium questions per week for Weeks 1 to 14 (Total 280 MCQs)
-- Evaluated from Easy to Hard

TRUNCATE TABLE public.questions CASCADE;


-- Update max scores of all test windows to 40 marks
UPDATE public.test_windows SET max_score = 40 WHERE week_number BETWEEN 1 AND 14;
